import { getRequestContext } from '@cloudflare/next-on-pages'
import { NextRequest, NextResponse } from 'next/server'

export const runtime = 'edge'

export async function DELETE(request: NextRequest, { params }: { params: { id: string } }) {
  try {
    const { env } = getRequestContext()
    if (!env || !env.DB) {
      return NextResponse.json({ error: "Database not available" }, { status: 500 })
    }

    const { id } = params

    // Check if product exists first (optional, but good for validation)
    const product = await env.DB.prepare("SELECT * FROM products WHERE id = ?").bind(id).first()
    if (!product) {
      return NextResponse.json({ error: "Product not found" }, { status: 404 })
    }

    await env.DB.prepare("DELETE FROM products WHERE id = ?").bind(id).run()

    return NextResponse.json({ success: true, message: "Product deleted" })
  } catch (error: any) {
    console.error("[v0] Delete Product Error:", error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function PUT(request: NextRequest, { params }: { params: { id: string } }) {
  try {
    const { env } = getRequestContext()
    if (!env || !env.DB) {
      return NextResponse.json({ error: "Database not available" }, { status: 500 })
    }

    const { id } = params
    const data = await request.json()
    const now = Date.now()

    // Dynamic update query builder
    const fields = []
    const values = []

    if (data.title !== undefined) { fields.push("title = ?"); values.push(data.title); }
    if (data.description !== undefined) { fields.push("description = ?"); values.push(data.description); }
    if (data.price !== undefined) { fields.push("price = ?"); values.push(data.price); }
    if (data.category !== undefined) { fields.push("category = ?"); values.push(data.category); }
    if (data.isActive !== undefined) { fields.push("isActive = ?"); values.push(data.isActive ? 1 : 0); }
    if (data.imageUrl !== undefined) { fields.push("imageUrl = ?"); values.push(data.imageUrl); }

    fields.push("updatedAt = ?"); 
    values.push(now);
    values.push(id); // For WHERE clause

    if (fields.length === 1) { // Only updatedAt was added
        return NextResponse.json({ success: true, message: "No changes detected" })
    }

    const query = `UPDATE products SET ${fields.join(", ")} WHERE id = ?`

    await env.DB.prepare(query).bind(...values).run()

    return NextResponse.json({ success: true, message: "Product updated" })
  } catch (error: any) {
    console.error("[v0] Update Product Error:", error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

